    response = requests.get(url)
    soup = BeautifulSoup(response.content, "html.parser")
    text = soup.get_text()
    questions = input("Enter your questions about the page: ")
    for question in questions.split(","):
        if question.lower() in text.lower():
            print(f"Answer: {text[text.lower().index(question.lower()):text.lower().index(question.lower())+len(question)]}")
        else:
            print(f"Sorry, I couldn't find the answer to '{question}'.")

