import requests
import json

def get_ciphered_text():
    ciphered_text = input("Enter the ciphered text: ")
    return ciphered_text

def decipher_text(ciphered_text):
    # Decipher the text
    deciphered_text = ""
    for char in ciphered_text:
        if char.isalnum():
            if char.isupper():
                deciphered_text += chr(65 + (ord(char) - 65) ^ 13)
            else:
                deciphered_text += chr(97 + (ord(char) - 97) ^ 13)
        else:
            deciphered_text += char
    return deciphered_text

def get_api_response(deciphered_text):
    # Call the API to get the response
    url = "https://api.example.com/translate"
    params = {"text": deciphered_text}
    response = requests.get(url, params=params)
    return response.json()

def display_translation(api_response):
    # Display the translation to the user
    print("Translation:", api_response["translation"])

def main():
    ciphered_text = get_ciphered_text()
    deciphered_text = decipher_text(ciphered_text)
    api_response = get_api_response(deciphered_text)
    display_translation(api_response)

if __name__ == "__main__":
    main()

